import json, re
from collections import Counter, defaultdict

with open('/tmp/all-obs-children-clean.json') as f:
    children = [c for c in json.load(f) if c['phase'] == 'new']

# Pattern detection
def categorize(c):
    title = c['title'].lower()
    body = c['body'].lower()
    cats = []

    # Specific recurring dedupe patterns
    if '_plan/' in body or 'stale `_plan/`' in title or 'stale _plan' in title.lower():
        cats.append('stale-plan-dir')

    # Doc drift patterns
    if any(x in title for x in ['stale', 'refresh', 'reconcile', 'update doc', 'sweep', 'docs/', 'readme']):
        cats.append('doc-drift')
    if any(x in body[:300] for x in ['stale', 'still describes', 'still references', 'docstring', 'still teaches', 'doc has drifted', 'doc still', 'pre-t2', 'pre-t3', 'pre-t4', 'pre-t5', 'pre-c1', 'pre-c2', 'pre-c3', 'pre-c4', 'pre-c5', 'predates t', 'predates c', "doesn't match", 'no longer match']):
        cats.append('doc-drift')

    # Vocabulary / rename drift  
    if any(x in body[:500] for x in ['nexus-clockworks', 'nexus-stacks', 'nexus-ledger', 'summon: sugar', 'brief: sugar', 'summon:', "'summon'", 'reserved_event_namespaces', 'piece-session', 'piece writ', "type: 'piece'", 'engine-failure stuck']):
        cats.append('rename-drift')

    # Brief drift (line numbers, file paths, etc)
    if any(x in title.lower() for x in ['stale', 'time-shifted', 'mis-state', 'misloca', 'mislocates']) and any(x in body[:300] for x in ['line numbers', 'line range', 'cite', 'mandate body cites', 'mislocated', 'pinned core', 'mistitle', 'brief']):
        cats.append('brief-drift')
    if 'brief' in body[:200] and 'stale' in body[:300]:
        cats.append('brief-drift')

    # DRY / code dedupe
    if any(x in title.lower() for x in ['duplicat', 'consolidat', 'unify', 'centralize', 'extract', 'shared', 'lift', 'deduplicate', 'harmoniz', 'collapse', 'standardize']):
        cats.append('dry-refactor')
    if any(x in body[:300] for x in ['duplicat', 'three places', 'four files', 'four sites', 'three sites', 'three files', 'each independently', 'verbatim']):
        cats.append('dry-refactor')

    # Test infra
    if any(x in title.lower() for x in ['test fixture', 'integration test', 'multi-apparatus boot', 'test harness', 'fakeguild', 'spider-test-fixture', 'boot scaffold', 'shared testing helper']):
        cats.append('test-infra')

    # Real bugs / soft hazards
    if any(x in title.lower() for x in ['bug', 'race', 'edge case', 'silently', 'silent', 'wrong', 'broken', 'forge', 'spoof', 'incorrect', 'collision', 'fail-loud', 'assertion that', 'pass by accident']):
        cats.append('real-hazard')
    if any(x in body[:300] for x in ['silently dropped', 'silently passes', 'race', 'spoof', 'forge', 'collid', 'misleading']):
        cats.append('real-hazard')

    # Forward design / open questions
    if any(x in title.lower() for x in ['decide', 'design', 'consider', 'evaluate', 'reconsider', 'should ', 'open question', 're-evaluate']):
        cats.append('design-q')
    if any(x in title.lower() for x in ['future commission', 'future work', 'follow-up', 'follow on']):
        cats.append('future-commission')

    # Operator UX
    if any(x in title.lower() for x in ['operator', 'cli', 'tool', 'badge', 'aria', 'ui', 'oculus', 'dashboard', 'render', 'help text', 'banner', 'log', 'machine-parseable', 'startup warning']):
        cats.append('ops-ux')

    # Cross-cutting infra
    if any(x in title.lower() for x in ['framework-wide', 'cross-package', 'kit-collision', 'kit-author', 'extract', 'hoisting', 'shared helper', 'shared module', 'shared constants', 'shared registry']):
        cats.append('cross-cutting')

    if not cats:
        cats.append('uncategorized')
    return cats

stats = Counter()
multi_cat = []
for c in children:
    cats = categorize(c)
    for cat in cats:
        stats[cat] += 1
    if len(cats) > 1:
        multi_cat.append((c['title'], cats))

print(f"Total unpromoted observations: {len(children)}")
print()
print("Category counts (each obs may have multiple tags):")
for cat, n in stats.most_common():
    print(f"  {n:4d}  {cat}")

# Find titles starting with same prefix
title_prefixes = Counter()
for c in children:
    words = c['title'].split()[:3]
    prefix = ' '.join(words)
    title_prefixes[prefix] += 1
print()
print("Repeated 3-word title prefixes (frequency >=3):")
for prefix, n in title_prefixes.most_common():
    if n >= 3:
        print(f"  {n:3d}  {prefix}")
EOF

