with open('/tmp/all-obs-children-clean.json') as f:
    children = [c for c in json.load(f) if c['phase'] == 'new']

# Cluster duplicates by topic via keyword sets in titles
clusters = defaultdict(list)
for c in children:
    title = c['title'].lower()
    body = c['body'][:500].lower()
    # Detect cluster keys
    if 'reserved_event_namespaces' in title or 'reserved_event_namespaces' in body:
        clusters['RESERVED_EVENT_NAMESPACES drift'].append(c)
    if 'nexus-clockworks' in title or 'nexus-clockworks' in body or 'nexus-stacks' in body:
        clusters['nexus-* legacy plugin id drift'].append(c)
    if 'summon:' in title or 'summon: sugar' in body or "'summon' sugar" in body or 'brief: sugar' in body or 'dropped sugar' in body:
        clusters['summon:/brief: sugar drift'].append(c)
    if '_plan/' in body or 'stale `_plan' in title or 'stale _plan' in title:
        clusters['stale _plan/ directory'].append(c)
    if 'piece' in title and ('rename' in title or 'stale' in title or 'reference' in title or 'astrolabe' in title or 'step' in title):
        clusters['piece → step rename drift'].append(c)
    if 'commission.' in title and ('event' in title or 'session' in title or 'sealed' in title or 'completed' in title or 'rename' in title or 'sweep' in title):
        clusters['commission.* event rename drift'].append(c)
    if 'session.' in title or 'session.ended' in body:
        if 'sweep' in title or 'rename' in title or 'subscribe' in title or 'session.start' in title or 'session.end' in title:
            clusters['session.* event rename drift'].append(c)
    if 'apparatus.stop' in body or 'stop()' in title or 'apparatus stop' in title:
        clusters['apparatus.stop() lifecycle gap'].append(c)
    if 'reckoner.md' in body or 'reckoner-apparatus' in body or 'old reckoner' in body or 'renamed-reckoner' in body or 'sentinel' in body:
        if 'rename' in title or 'sentinel' in title or 'reckoner.md' in body[:300]:
            clusters['Reckoner rename / split / sentinel'].append(c)
    if 'terminal_statuses' in body or 'four files' in body[:300] or 'set' in title.lower() and 'terminal' in title.lower():
        if 'terminal' in body[:200].lower() or 'terminal_statuses' in body:
            clusters['TERMINAL_STATUSES dedupe'].append(c)
    if 'classification' in body and ('phase ===' in body or 'phase string' in body.lower() or 'mandate phase' in body.lower()):
        clusters['mandate-phase string usage / classification migration'].append(c)
    if 'core-api.md' in body and ('stale' in body or 'refresh' in body or 'no longer' in body or 'does not exist' in body):
        clusters['core-api.md drift'].append(c)
    if 'schema.md' in body and ('stale' in body or 'refresh' in body or 'no longer' in body or 'drift' in body):
        clusters['reference/schema.md drift'].append(c)
    if 'badge' in title or 'aria' in title.lower():
        clusters['dashboard polish (badges, accessibility)'].append(c)
    if 'kit-collision' in title or 'kit collision' in body.lower() or 'collision polic' in body.lower():
        clusters['Kit-collision validator / policy'].append(c)
    if 'em-dash' in title or 'em-dash' in body[:300] or "'—'" in body[:300]:
        clusters['em-dash placeholder dedupe'].append(c)
    if 'tool auto-builder' in title.lower() or ('program.ts' in body and 'auto-builder' in body):
        clusters['CLI tool auto-builder gaps'].append(c)
    if 'vocabulary' in title.lower() or 'guild-vocabulary' in body:
        clusters['guild-vocabulary updates'].append(c)
    if 'kebab' in title or 'kebab-suffix' in body:
        clusters['kebab-suffix grammar'].append(c)

print(f"Cluster sizes (observations potentially mergeable):\n")
for cluster, items in sorted(clusters.items(), key=lambda x: -len(x[1])):
    print(f"  {len(items):3d}  {cluster}")
